vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    // Build the graph
    vector<vector<long long>> graph(c + 1);
    for (auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        graph[u].push_back(v);
        graph[v].push_back(u);
    }

    // DSU (Disjoint Set Union) to find connected components
    vector<long long> parent(c + 1);
    vector<long long> rank(c + 1);
    vector<bool> online(c + 1, true);

    // Initialize DSU
    for (long long i = 1; i <= c; ++i) {
        parent[i] = i;
        rank[i] = 1;
    }

    // Find function with path compression
    auto find = [&](long long x) -> long long {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    // Union function
    auto unionSets = [&](long long x, long long y) -> void {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX != rootY) {
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else {
                parent[rootY] = rootX;
                if (rank[rootX] == rank[rootY]) {
                    ++rank[rootX];
                }
            }
        }
    };

    // Build the DSU for the initial connected components
    for (long long i = 1; i <= c; ++i) {
        for (auto& neighbor : graph[i]) {
            if (i < neighbor) {
                unionSets(i, neighbor);
            }
        }
    }

    // For each component, store the minimum id in it
    unordered_map<long long, long long> minIdInComponent;
    for (long long i = 1; i <= c; ++i) {
        minIdInComponent[find(i)] = min(minIdInComponent[find(i)], i);
    }

    vector<long long> result;

    for (auto& query : queries) {
        long long type = query[0];
        long long x = query[1];

        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                long long root = find(x);
                long long minId = minIdInComponent[root];
                if (online[minId]) {
                    result.push_back(minId);
                } else {
                    result.push_back(-1);
                }
            }
        } else {
            online[x] = false;
            // Update minIdInComponent if x was the min in its component
            long long root = find(x);
            if (minIdInComponent[root] == x) {
                // Find the new min in the component
                long long newMin = numeric_limits<long long>::max();
                for (long long i = 1; i <= c; ++i) {
                    if (find(i) == root && online[i]) {
                        newMin = min(newMin, i);
                    }
                }
                minIdInComponent[root] = newMin;
            }
        }
    }

    return result;
}

